css:
/*【主流杂志｜粉黑】作者：易碎蝶
①本美化免费发布于QQ小群（或可能本人发在旅程），禁止二传二改
②部分代码用到了其他老师分享的，有标注~
③仅限于在正规渠道由本人发布后下载获取，一切其他方式获得皆视为二传，抓到必究
④🍃⭕️←这个是可以调整的部分*/

/* ====== 全局字体====== */
@import url("https://fontsapi.zeoseven.com/19/main/result.css");

body {
    font-family: "LXGW Neo XiHei";
    font-weight: normal;
    font-size: 14px;
}
/*———————— 顶栏 ————————*/
#top-bar {
    position: fixed;
    top: 5px; /* 统一在这里控制上边距 */
    left: 50%;
    transform: translateX(-50%);
    width: 58%; /* 这是电脑端的宽度 */
    height: 30px;
    pointer-events: none;
    z-index: 1000;
    background: none;
    border: 0;
    box-shadow: none;
    overflow: visible;
    transition: width 0.3s ease; /* 添加平滑过渡效果 */
}

#top-bar::before {
    content: "";
    position: absolute; /* 核心修正：从 fixed 改为 absolute */
    top: 0;
    left: 0;
    width: 100%; /* 宽度继承父元素 #top-bar */
    height: 100%; /* 高度继承父元素 #top-bar */
    background: rgba(0, 0, 0, 0.4); 
    backdrop-filter: blur(32px); 
    -webkit-backdrop-filter: blur(12px); 
    border-radius: 20px; 
    box-shadow: 
        0 0 0 1.3px #f4c2d7, 
        0px 10px 20px rgba(244, 194, 215, 0.1); 
    z-index: 4; 
    pointer-events: auto;
}

/* 手机端自适应 */
@media (max-width: 786px) {
    #top-bar {
        width: 95%; /* 在手机上，宽度变为95% */
    }
}

/* ⭕️顶栏装饰层 */
#top-bar::after {
    content: "";
    position: fixed;
    background: url("data:image/png;base64,iVBORw0KGgoAAAANSUhEUgAAAAEAAAABCAQAAAC1HAwCAAAAC0lEQVR42mNkYAAAAAYAAjCB0C8AAAAASUVORK5CYII=") no-repeat center / contain;
    /* 1. 设置一个具体的宽度，您可以根据图片和设计需求调整这个数值 */
    width: 400px; 
    height: 210px;
    top: -88px;
    /* 2. 移除 right 属性，改用 left: 50% */
    left: 50%;
    z-index: 6;
    pointer-events: none;
    transform-origin: top center;
    /* 3. 使用 transform 将元素向左移动自身宽度的一半，实现精确居中 */
    transform: translateX(-50%);
}


/* —————面板背景———— */
.drawer-content {
  background-image: url(''); /* 面板背景 */
  background-size: cover; 
  background-position: center; 
  background-repeat: no-repeat; 
  background-attachment: fixed;
  margin-top: 9px; /* 顶部下移*/
}
/*毛玻璃@LiitleYE*/
body.no-blur .drawer-content {
background: rgba(0, 0, 0, 0.5); 
  backdrop-filter: blur(40px) !important;
}


/* ===== ⭕️楼层箭头、计数器核心 ===== */
.fa-chevron-right:before,
.fa-chevron-left:before,
.fa-arrow-right:before {
  content: "" !important;
  display: none !important; 
}

.fa-chevron-left,
.fa-chevron-right {
  display: inline-block;
  width: 14px;
  height: 14px; 
  min-width: 0;
  background: center/contain no-repeat;
}

.fa-chevron-left {
  background-image: url('data:image/png;base64,iVBORw0KGgoAAAANSUhEUgAAAAEAAAABCAQAAAC1HAwCAAAAC0lEQVR42mNkYAAAAAYAAjCB0C8AAAAASUVORK5CYII='); /* 左 */
  margin-bottom: -10px; 
}
.fa-chevron-right {
  background-image: url('data:image/png;base64,iVBORw0KGgoAAAANSUhEUgAAAAEAAAABCAQAAAC1HAwCAAAAC0lEQVR42mNkYAAAAAYAAjCB0C8AAAAASUVORK5CYII='); /* 右 */
  margin-bottom: -10px; 

}

/* ===== 楼层计数器样式 ===== */
.swipes-counter {
  font-size: 9px;
  font-weight: 540;
  opacity: 0.5 !important;
  color: #e8d6dc !important;
  display: flex;
  justify-content: center;
  align-self: center;
  z-index: 3;
  min-width: 0;
  height: 20px;
  padding: 30px 10px 0; /* ①；需要联合②调整 */
  margin: 0 10px;
  margin-bottom: -10px;/*②；需要联合①调整*/
}

/* ==============================================
🦋气泡拼接开始🦋 *==============================================*/

/* 🍃上层装饰层、拼接气泡顶部 */
.mes::before {
  content: "";
  position: absolute;
  top: -129px; /* 【上下】(负值向上) */
  left: -13px; /* 【左右】 */
  width: 420px; /* 【宽度/大小】 */
  height: 530px; /* 【高度/大小】 */
  background-image: url('data:image/png;base64,iVBORw0KGgoAAAANSUhEUgAAAAEAAAABCAQAAAC1HAwCAAAAC0lEQVR42mNkYAAAAAYAAjCB0C8AAAAASUVORK5CYII='); 
  background-size: contain; 
  background-repeat: no-repeat; 
  z-index: -2; 
  pointer-events: none; 
}

/* 🍃下层装饰层、拼接气泡尾部 */
.mes::after {
  content: "";
  position: absolute;
  bottom: -60px; /* 【上下】(负值向下) */
  right: 135px; /* 下层装饰层【左右】 */
  width: 120px; /* 【宽度/大小】 */
  height: 90px; /* 【高度/大小👁会影响最新消息的底部留白，不可调太高，宽度拉不动再调高一点】 */
  background-image: url('data:image/png;base64,iVBORw0KGgoAAAANSUhEUgAAAAEAAAABCAQAAAC1HAwCAAAAC0lEQVR42mNkYAAAAAYAAjCB0C8AAAAASUVORK5CYII='); 
  background-size: contain; 
  background-repeat: no-repeat; 
  z-index: -4; 
  pointer-events: none; 
}

/* 🍃 中层气泡*/
.mes {
  z-index: -3;
  max-width: 1000px;
  width: 100%;
  margin: 220px auto 0px;
  border-radius: 10px;
  position: relative;
  overflow: visible;
  border: 1px solid rgba(244, 194, 215, 0.2); /* 调整描边透明度 */
}

/*毛玻璃@LiitleYE*/
body.no-blur .mes {
background: rgba(0, 0, 0, 0.5); 
  backdrop-filter: blur(70px) !important;
}

/*——————🍃文本边距——————*/

.mes_text,
.mes_reasoning {
    font-weight: 00;
    line-height: calc(var(--mainFontSize) + .5rem);
    text-align: left; 
    overflow-wrap: anywhere;

    /* ⭕️文字边距核心*/

    --top-padding:6rem; /* 顶部 */
    --bottom-padding: 2rem; /* 底部 */
    --left-padding: 0rem; /* 左边距 */
    --right-padding: 0.7rem; /* 右边距 */

/*👁没啥用但不能删↓*/
    padding-top: var(--top-padding);
    padding-bottom: var(--bottom-padding);
    padding-left: var(--left-padding);
    padding-right: var(--right-padding);
    max-width: 100%;
    margin: 0; 
}

/* ==============================================
🦋气泡拼接结束🍃头像美化开始============================================== */


/*⭕️头像框*/
.mesAvatarWrapper {
  position: absolute;
  top: -147px;
  left: 28%;
  transform: translateX(-50%);
  z-index: -1;
  width: 70px;  
  height: 70px; 
  overflow: visible; 
}

/* ⭕️头像框位置与大小调整核心 */
.mesAvatarWrapper::after {
  content: "";
  position: absolute;
  top: 51%;/* 【上下】 */
  left: 172%;/* 【左右】 */
  width: 397%;  /* 【框宽度】 */
  height: 257%; /* 【框高度】 */
  display: block;

  /* ⭕️头像框链接放置处 */
  background-image: url('data:image/png;base64,iVBORw0KGgoAAAANSUhEUgAAAAEAAAABCAQAAAC1HAwCAAAAC0lEQVR42mNkYAAAAAYAAjCB0C8AAAAASUVORK5CYII=');/*←🍃*/
  background-size: 100% 100%;
  background-repeat: no-repeat;
  background-position: center;
  transform: translate(-50%, -50%);
  z-index: 1; 

}

.mesAvatarWrapper img {
  position: relative;
  z-index: -1; 
}

/* ⭕️头像位置 */
.mesAvatarWrapper {
  position: absolute;
  top: -120px;           /* 【负值向上】 */
  left: 12%;            /* 【头像左右】 */
  transform: translateX(-50%);
  z-index: -1;
}

/* ⭕️头像尺寸*/
.mesAvatarWrapper .avatar {
  /* 🍃头像尺寸 */
  width: 172px;           /* 宽度 */
  height: 112px;          /* 高度 */
  transform: rotate(0deg); /* 旋转 */
}
.mesAvatarWrapper .avatar img {
  width: 100%;
  height: 100%;
  object-fit: cover;
}



/* ==============================================
🦋头像美化结束🍃文字效果美化开始============================================== */

/* === 设置选项=== */
small {
  color: #ffeef4 !important;
  opacity: 0.8;
}
.toggle-description {
    color: #ffeef4;
}
#completion_prompt_manager .completion_prompt_manager_header div {
    color: #ffeef4; /*字符*/
}

.fa-solid::before, .fa-regular::before {
    vertical-align: middle;
    text-align: center;
}

.right_menu_button {
    padding: 1px;
    filter: none;
    color: #ffeef4 !important; /* 更新文字颜色 */
}

/* === 预设区文字颜色 === */
/* 选中 */
#completion_prompt_manager #completion_prompt_manager_list .completion_prompt_manager_prompt_name .prompt-manager-inspect-action {
  color: #ffeef4;
}

/* 未选 */
#completion_prompt_manager #completion_prompt_manager_list .completion_prompt_manager_prompt_disabled .completion_prompt_manager_prompt_name, 
#completion_prompt_manager #completion_prompt_manager_list .completion_prompt_manager_prompt_disabled .completion_prompt_manager_prompt_name .prompt-manager-inspect-action {
  color: #6f565f;
}

/* 星号等标识颜色*/
#completion_prompt_manager #completion_prompt_manager_list .completion_prompt_manager_prompt .completion_prompt_manager_prompt_name .fa-solid {
    color: #c3a5b0;
}


/* 代码块 */
code, pre {
background: rgba(40, 30, 40, 0.9) !important;
color: #eae2e5 !important;
border: 0px solid rgba(208, 128, 172, 0.5) !important;
box-shadow: 
  inset 3px 3px 4px rgba(208, 128, 172, 0),
  0 0 15px rgba(208, 128, 172, 0.4),
  3px 3px 0px rgba(107, 102, 66, 0.1) !important;
border-radius: 15px 0px 15px 0px !important;
}
/* 引用气泡 */
.mes_text q {
  background: linear-gradient(90deg, rgba(208, 128, 172, 0.3) 0%, rgba(255, 255, 255, 0) 100%) !important; 
  border-radius: 10px !important;
  font-weight: 300;
  text-shadow: 0 0 8px rgba(208, 128, 172, 0.7), 
               0 0 12px rgba(208, 128, 172, 0.5),
               0 0 16px rgba(208, 128, 172, 0.3) !important;
  box-shadow: 0 0 5px rgba(208, 128, 172, 0.4) inset !important;
  animation: breathing-light 3s ease-in-out infinite !important;
font-style: italic !important;
}


/* 引用区块 */
.mes_text blockquote, 
.mes_reasoning blockquote {
  border-left: 2px solid #d080ac !important; 
  background: linear-gradient(90deg, rgba(208, 128, 172, 0.15) 0%, rgba(255, 255, 255, 0) 100%) !important; 
  color: #e6d0d9 !important; 
!important; 
  border-radius: 0px 15px 0px 15px !important;

}
/* 斜体 */
em, i {
  background: linear-gradient(to bottom, 
    rgba(2, 255, 247, 0) 90%, 
    rgba(158, 148, 151, 0.72) 90%) !important; 
  font-style: italic !important; 
}
/* ==============================================
🦋文字效果美化结束🍃零碎美化开始============================================== */

/*—— 🍃楼层 ——*/

.mes .mesIDDisplay {
    position: fixed;
    top: 48px;
    left: 178.5px;                    /* 从左侧开始定位 */
    transform: none;            /* 移除所有变换效果 */
    z-index: 2;
    margin-top: 0px;
    text-align: left;           /* 文字左对齐 */
    width: auto;                /* 宽度自适应内容 */
    white-space: nowrap;        /* 防止文字换行 */
    padding: 0 10px;            /* 添加左右内边距 */


    display: inline-flex; 
    align-items: center;  
    gap: 2px;            /* 【左右文字间距】 */

    cursor: default;
    opacity: 1;
    font-size: calc(var(--mainFontSize) * 0.7);
    font-weight: 300;
    color: #e8d6dc;      /* 【主文字颜色】 */
}


/* 左侧文字 */
.mes .mesIDDisplay::before {
    content: var(--left-text, "A • 第"); /* 【左侧文字内容】 */
    white-space: nowrap;  
    color: var(--left-color, #e8d6dc); /* 【左侧文字颜色】 */
    font-weight: 300;
}

/* 右侧文字 */
.mes .mesIDDisplay::after {
    content: var(--right-text, "期杂志"); /* 【右侧文字内容】 */
    white-space: nowrap;  
    color: var(--right-color, #e8d6dc); /* 【右侧文字颜色】 */
    font-weight: 300;
}

/*—— 🍃基础信息【时间戳、角色昵称等】 ——*/

/* ⭕️消息文字上边距留白核心调整 */
.mes_block {
  position: relative;
  margin-top: -120px;  
  overflow: visible;
}

/* ⭕️角色名称核心调整 */
.mes_block .ch_name {
  position: relative;
  top: -58px; /* 上下 */
  left: 45px;
  max-width: calc(100% - 105px); 
  min-height: 0px;
  z-index: 10; 
 font-size: 0.60em;
  font-weight: 800;
  letter-spacing: 0.9px;
white-space: nowrap;
}


/* 角色昵称颜色 */
.mes_block .ch_name {
  color: #e8d6dc !important; 
  text-shadow: none !important;
  -webkit-text-stroke: 0 !important; 
}

/* 时间戳颜色 */
.timestamp {
  color: #e8d6dc !important; 
  opacity: 1 !important; 
}


/* ⭕️时间戳核心调整 */
.timestamp {
  position: absolute;
  top: 52px;                /* 上下 */
  left: 132px;                /* 左右 */
  width: 300%; 
  font-size: 7px;            /* 字体大小 */
  font-weight: 500;          /* 字体粗细 */
  transform: rotate(0deg);   /* 旋转 */
  white-space: nowrap;
}

/* 左侧文字 */
.timestamp::before {
  content: "• 本期发布时间｜";       /*左侧文字 */
  color: #e8d6dc;            /* 左侧文字颜色 */
  display: inline;
  padding-right: 0px;        /* 右侧间距（分隔时间戳） */
  pointer-events: none;
}

/* 右侧文字 */
.timestamp::after {
  content: "";       /* 右侧文字 */
  color: #967aa1;            /* 右侧文字颜色 */
  display: inline;
  padding-left: 0px;         /* 左侧间距（分隔时间戳） */
  pointer-events: none;
}


/* ⭕️编辑按钮核心调整 */
.mes_buttons {
  position: relative;
  top: 116px; /*上下*/
  left: 73px;/*左右*/
  z-index: 30;
  padding: 20px; 
  min-height: 36px;
  box-sizing: border-box;
  transform: rotate(0deg); /* 旋转 */
}

.mes_edit_buttons {
    display: none;
    flex-direction: row;
    column-gap: 5px;
    float: right;
    cursor: pointer;
    padding-bottom: 5px;
    filter: none; /*移除阴影*/
    transition: 0.3s ease-in-out;

    /* ⭕编辑菜单位置核心调整⭕ */
    position: relative;
    top: 160px;  /* 负数上移 | 正数下移  */
    right: 0px;   /* 负数右移 | 正数左移  */
  transform: rotate(0deg); /* 旋转 */
}
.mes_edit_down.menu_button.fa-solid.fa-chevron-down.interactable.disabled {
    filter: none !important;
}
.mes_button, .extraMesButtons>div {
cursor: pointer;
    transition: opacity 0.2s ease-in-out;
    filter: drop-shadow(0px 0px 0px #ffffff) !important;
    /* ⭕设置省略号菜单颜色 */
    color: #e8d6dc !important;
opacity: 0.4 !important; 
}


/*—— 计时器&字符——*/
.mes {
  position: relative; 
}

.mes .mes_timer,
.mes .tokenCounterDisplay {
  position: fixed; 
  z-index: 3; 
  cursor: default;
opacity: 1;/*透明度*/
  white-space: nowrap; 
  font-size: calc(var(--mainFontSize) * 0.7);/*文字大小*/
  font-weight: 400;/*文字粗细*/
  padding: 0;
  top: var(--element-top, 240px);
  left: var(--element-left, 50%);
  transform: translateX(var(--element-translate, -50%));
}


/* === ⭕️计时器核心 === */
.mes .mes_timer {
  --element-top: var(--timer-top, 87px); /*【🍃计时器上下】*/
  --timer-left: 189px; /* 🍃计时器左右 */
  --timer-translate: 0; 
  text-align: left; 
  left: var(--timer-left);
  transform: translate(var(--timer-translate), -50%);

  /* 文字内容控制 */
  --timer-prefix: "C • "; /* 【🍃前缀】 */
  --timer-suffix: " 售空"; /* 【🍃后缀】 */

  --timer-main-color: #e8d6dc; /* 【🍃计时器颜色】 */
  --timer-prefix-color: #e8d6dc; /* 【🍃前缀颜色】 */
  --timer-suffix-color: #e8d6dc; /* 【🍃后缀颜色】 */

  color: var(--timer-main-color);
}

/* 计时器文字控制 */
.mes .mes_timer::before {
  content: var(--timer-prefix); /* 前缀文字 */
  color: var(--timer-prefix-color);
  padding-right: 0px;
}
.mes .mes_timer::after {
  content: var(--timer-suffix); /* 后缀文字 */
  color: var(--timer-suffix-color);
  padding-left: 0px;
}

/* === 字符计数器单独设置 === */
.mes .tokenCounterDisplay {
  text-align: left;
  --element-top: var(--counter-top, 65px); /* 【🍃字符计数器上下】 */
  --element-left: var(--counter-left, 270%); /* 【🍃字符计数器左右】 */
  --element-translate: var(--counter-translate, -0%); 

  --counter-prefix: "B • 总订阅者"; /* 【🍃前缀】 */
  --counter-suffix: ""; /* 【🍃后缀】 */

  --counter-main-color: #e8d6dc; /* 【🍃计数器颜色】 */
    --counter-prefix-color: #e8d6dc; /* 【🍃前缀颜色】 */
  --counter-suffix-color: #e8d6dc; /* 【🍃后缀颜色】 */
  color: var(--counter-main-color);

}

.mes .tokenCounterDisplay::before {
  content: var(--counter-prefix); /* 前缀文字 */
  color: var(--counter-prefix-color);
  padding-right: 0px;
}
.mes .tokenCounterDisplay::after {
  content: var(--counter-suffix); /* 后缀文字 */
  color: var(--counter-suffix-color);
  padding-left: 0px;
}

/*—— ⭕️外显思维链 ——*/
.mes_reasoning_header {
  position: absolute;
  z-index: 9999;
  top: 85px;
  left: 60%;
  transform: translateX(-50%);
  cursor: pointer;
  user-select: none;
  font-size: calc(var(--mainFontSize) * 0.75);
  transition: all 0.3s ease;

  padding: 1px 15px;
  background: linear-gradient(90deg, 
              rgba(255, 197, 217, 0.5) 0%, 
              rgba(255, 255, 255, 0) 100%);
  border: none;
  border-radius: 0;
  box-shadow: 
    0 4px 12px rgba(107, 102, 66, 0.08),
    0 2px 4px rgba(107, 102, 66, 0.04);
  color: #000000;
  backdrop-filter: blur(4px);
}

.mes_reasoning_header:hover {
  transform: translateX(-50%) translateY(1px);
  opacity: 0.92;
  background: linear-gradient(90deg, 
              rgba(255, 197, 217, 0.95) 0%, 
              rgba(255, 255, 255, 0.1) 100%);
  box-shadow: 
    0 2px 6px rgba(107, 102, 66, 0.05),
    0 1px 2px rgba(107, 102, 66, 0.02);
}

.mes_reasoning_header_title {
  position: relative;
  display: inline-block;
  top: 0px;
  left: -0px;
  color: #a28d9a;
  font-weight: 400;
  letter-spacing: 0.5px;
  text-shadow: 0 1px 1px rgba(255, 255, 255, 0.7);
}

.mes_reasoning {
  position: relative;
  top: -190px;
  display: block;
  margin: 235px 0px -240px;

  color: #8a7a78;
  background: linear-gradient(90deg, 
              rgba(255, 197, 217, 0.12) 0%, 
              rgba(255, 255, 255, 0) 70%);
  border: none;
  box-shadow: 
    0 8px 24px rgba(107, 102, 66, 0.1),
    0 2px 6px rgba(107, 102, 66, 0.05);
  padding: 18px 20px;
  line-height: 1.7;
  border-radius: 0px;

  background-image: none;
  backdrop-filter: blur(8px);
}
.mes_reasoning_header_title {
  /* 隐藏原始文本 */
  font-size: 0; 
  color: transparent; 
}

.mes_reasoning_header_title::before {
  /*⭕️思维链文字diy */
  content: "𝗟𝗲𝗶𝘀𝘂𝗿𝗲 𝗧𝗶𝗺𝗲";
  font-size: 7px; /* 字号 */
  color: #fff7f9;
  font-style: italic; 
  font-weight: 200; 
}

