  -webkit-box-sizing: border-box;
  box-sizing: border-box;
}

/* 标题字体 */
.toast-title {
  font-weight: 700;
}

.toast {
  position: relative;
  padding: 15px 20px 15px 65px; /* 左侧留出图片空间 */
  min-height: 60px;
}

/* 错误提示 */
body #toast-container .toast-error {
    background-color: #000000;
}

/* 成功提示 */
body #toast-container .toast-success {
    background-color: #000000;
}

/* 警告提示 */
body #toast-container .toast-warning {
    background-color: #000000;
}

/* 信息提示 */
body #toast-container .toast-info {
    background-color: #000000;
}

/* 原始信息 */
body #toast-container .toast-info {
    background-color: #000000;
}

.toast::before {
  content: "";
  position: absolute;
  left: 17px;
  top: 50%;
  transform: translateY(-50%);
  width: 20px;
  height: 20px;
  background: 
    /* 默认图片  */
    url("data:image/png;base64,iVBORw0KGgoAAAANSUhEUgAAAAEAAAABCAQAAAC1HAwCAAAAC0lEQVR42mNkYAAAAAYAAjCB0C8AAAAASUVORK5CYII=")

    center/contain no-repeat;
}

/* 成功弹窗 */
.toast-success::before {
  background-image: 
    url("data:image/png;base64,iVBORw0KGgoAAAANSUhEUgAAAAEAAAABCAQAAAC1HAwCAAAAC0lEQVR42mNkYAAAAAYAAjCB0C8AAAAASUVORK5CYII=")
    ;
}

/* 错误弹窗 */
.toast-error::before {
  background-image: 
    url("data:image/png;base64,iVBORw0KGgoAAAANSUhEUgAAAAEAAAABCAQAAAC1HAwCAAAAC0lEQVR42mNkYAAAAAYAAjCB0C8AAAAASUVORK5CYII=")
    ;
}

/* 消息内容区 */
.toast-message {
  line-height: 1.4;
  padding-top: 0px;
  font-size: 12px;
}

/* 文字颜色 */
#toast-container * {
    color: #e8d6dc !important; 
}

#toast-container>.toast-success, 
#toast-container>.toast-error {
    background-image: none !important;
}

/*————加载齿轮————*/
#load-spinner {
    background: url("data:image/png;base64,iVBORw0KGgoAAAANSUhEUgAAAAEAAAABCAQAAAC1HAwCAAAAC0lEQVR42mNkYAAAAAYAAjCB0C8AAAAASUVORK5CYII=") no-repeat center center;
    background-size: contain;

    animation: float 3s ease-in-out infinite; 
}

/* 动画 */
@keyframes float {
    0%, 100% {
        transform: translateY(0); /* 起始和结束位置 */
    }
    50% {
        transform: translateY(-25px); /* 向上浮动 */
    }
}

/* 隐藏原图标 */
#load-spinner::before,
#load-spinner::after {
    display: none;
}
